on_write:
let res = #{ action: "Allow" };
if payload.contains("model_type") {
    res.parsed_model = payload.model_type;
} else {
    res.action = "Reject";
}
res

on_read:
let res = #{ payload: payload };
if payload.model_type == "graph" || payload.model_type == "document" {
    res.match_found = true;
} else {
    res.match_found = false;
}
res
